1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description:
5	-- Generic register slave endpoint on AXI-Lite bus
6	-- Supports a configurable number of write and read vectors.
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_arith.all;
20	use ieee.std_logic_unsigned.all;
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiLitePkg.all;
25	
26	entity AxiLiteRegs is
27	   generic (
28	      TPD_G           : time                  := 1 ns;
29	      RST_POLARITY_G  : sl                    := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
30	      RST_ASYNC_G     : boolean               := false;
31	      NUM_WRITE_REG_G : integer range 1 to 32 := 1;
32	      INI_WRITE_REG_G : Slv32Array            := (0 => x"0000_0000");
33	      NUM_READ_REG_G  : integer range 1 to 32 := 1);
34	   port (
35	      -- AXI-Lite Bus
36	      axiClk         : in  sl;
37	      axiClkRst      : in  sl;
38	      axiReadMaster  : in  AxiLiteReadMasterType;
39	      axiReadSlave   : out AxiLiteReadSlaveType;
40	      axiWriteMaster : in  AxiLiteWriteMasterType;
41	      axiWriteSlave  : out AxiLiteWriteSlaveType;
42	      -- User Read/Write registers
43	      writeRegister  : out Slv32Array(NUM_WRITE_REG_G-1 downto 0);
44	      readRegister   : in  Slv32Array(NUM_READ_REG_G-1 downto 0) := (others => (others => '0')));
45	end AxiLiteRegs;
46	
47	architecture rtl of AxiLiteRegs is
48	
49	   subtype WriteRegArray is Slv32Array(writeRegister'range);
50	
51	   function writeRegIni(iniVal : Slv32Array) return WriteRegArray is
52	   begin
53	      if (iniVal'length = 1) then
54	         return (others => iniVal(0));
55	      else
56	         return iniVal;
57	      end if;
58	   end function writeRegIni;
59	
60	   type RegType is record
61	      writeRegister : WriteRegArray;
62	      axiReadSlave  : AxiLiteReadSlaveType;
63	      axiWriteSlave : AxiLiteWriteSlaveType;
64	   end record RegType;
65	
66	   constant REG_INIT_C : RegType := (
67	      writeRegister => writeRegIni(INI_WRITE_REG_G),
68	      axiReadSlave  => AXI_LITE_READ_SLAVE_INIT_C,
69	      axiWriteSlave => AXI_LITE_WRITE_SLAVE_INIT_C);
70	
71	   signal r   : RegType := REG_INIT_C;
72	   signal rin : RegType;
73	
74	begin
75	
76	   assert (((INI_WRITE_REG_G'left = writeRegister'left)
77	            and (INI_WRITE_REG_G'right = writeRegister'right)
78	            and (INI_WRITE_REG_G'ascending = writeRegister'ascending))
79	           or (INI_WRITE_REG_G'length = 1))
80	      report "INI_WRITE_REG_G must have either one element or cover the same range as writeRegs"
81	      severity failure;
82	
83	   comb : process (axiClkRst, axiReadMaster, axiWriteMaster, r, readRegister) is
84	      variable v      : RegType;
85	      variable regCon : AxiLiteEndPointType;
86	   begin
87	      -- Latch the current value
88	      v := r;
89	
90	      -- Determine the transaction type
91	      axiSlaveWaitTxn(regCon, axiWriteMaster, axiReadMaster, v.axiWriteSlave, v.axiReadSlave);
92	
93	      -- Map the read registers = [0x000:0x0FF]
94	      for i in NUM_READ_REG_G-1 downto 0 loop
95	         axiSlaveRegisterR(regCon, toSlv((i*4)+0, 9), 0, readRegister(i));
96	      end loop;
97	
98	      -- Map the write registers = [0x100:0x1FF]
99	      for i in NUM_WRITE_REG_G-1 downto 0 loop
100	         axiSlaveRegister(regCon, toSlv((i*4)+256, 9), 0, v.writeRegister(i));
101	      end loop;
102	
103	      -- Closeout the transaction
104	      axiSlaveDefault(regCon, v.axiWriteSlave, v.axiReadSlave, AXI_RESP_DECERR_C);
105	
106	      -- Synchronous Reset
107	      if (RST_ASYNC_G = false and axiClkRst = RST_POLARITY_G) then
108	         v := REG_INIT_C;
109	      end if;
110	
111	      -- Register the variable for next clock cycle
112	      rin <= v;
113	
114	      -- Outputs
115	      axiReadSlave  <= r.axiReadSlave;
116	      axiWriteSlave <= r.axiWriteSlave;
117	      writeRegister <= r.writeRegister;
118	
119	   end process comb;
120	
121	   seq : process (axiClk, axiClkRst) is
122	   begin
123	      if (RST_ASYNC_G and axiClkRst = RST_POLARITY_G) then
124	         r <= REG_INIT_C after TPD_G;
125	      elsif rising_edge(axiClk) then
126	         r <= rin after TPD_G;
127	      end if;
128	   end process seq;
129	
130	end architecture rtl;
